import React from 'react';

const Menu = ({header, items, active, setActive}) => {
    return(
        // <div className="menu">
        //     <div className="blur"/>
        //     <div className="menu__content">
        //         <div className="menu__header">{header}</div>
        //         <ul>
        //             {items.map(item =>
        //                 <li>
        //                     <a href={item.href}>{item.value}</a>
        //                 </li>
        //             )}
        //         </ul>
        //     </div>
        // </div>

                    <header className={active ? 'menu active' : 'menu'} onClick={() => setActive(false)}>
                        <div className="container">
                            <div className="header_inner" onClick={e => e.stopPropagation()}>
                                <a className="logo" href="#" data-scroll="#main_section">MoGo</a>

                                <nav className="nav">
                                        <ul>
                                            {items.map(item =>
                                                <li>
                                                    <a href={item.href}>{item.value}</a>
                                                </li>
                                            )}
                                        </ul>
                                </nav>

                                <button className="nav_toggle" type="menu" id="nav_toggle">
                                    <i className="fa-solid fa-bars"></i>
                                </button>
                            </div>
                        </div>
                    </header>
    );
}

export default Menu;
